UPDATE vibe.users
position = #{position,jdbcType=VARCHAR}, remaining_vacation = #{remainingVacation,jdbcType=NUMERIC}, is_admin = #{isAdmin,jdbcType=NUMERIC}, team = #{team,jdbcType=VARCHAR}, is_team_leader = #{isTeamLeader,jdbcType=NUMERIC},
WHERE id = #{id}

